import * as vscode from "vscode";
import { createOffsetmapOfBrackets } from "./mapCreater";
import { checkBracketMatching } from "./checkBrackets";
import { createPropertiesMap } from "./mapCreater";

export class FindBlocks {

    document: vscode.TextDocument;
    diagnosticCollectionLocal: vscode.Diagnostic[] = [];
    constructor(documentLocal:vscode.TextDocument) {
        this.document = documentLocal;
        this.diagnosticCollectionLocal = [];
    }


    findHtmlBlocks(): void {
        const htmlTagRegex = new RegExp(String.raw`\bhtml\s*\`([\s\S]*?)\``, "g");
        const htmlTagsPositionResults: number[] = []; // includes start and end offset of first letter of the html block(excluding html` and )
        let match: RegExpExecArray | null;
        while ((match = htmlTagRegex.exec(this.document.getText())) !== null) {
        htmlTagsPositionResults.push(match!.index+5); htmlTagsPositionResults.push(match![0].length + match!.index -1);
        const offsetsOfBracketsMap = createOffsetmapOfBrackets(htmlTagsPositionResults,this.document);
        //console.log(match);
        checkBracketMatching(offsetsOfBracketsMap,this.diagnosticCollectionLocal,this.document)
        htmlTagsPositionResults.pop();htmlTagsPositionResults.pop();
        }
    }

    findProperties(): void {
        const propertyRegex = new RegExp(String.raw`@property\s*\([\s\S]*?\)\s*([A-Za-z_][A-Za-z0-9_]*)`, "g");
        const propertyPositionsResults: number[] = []; // includes start and end offset of first letter of the property declaration(excluding @property(...) and ; or { )
        let matchProp: RegExpExecArray | null;
        console.log("i was here");
        while ((matchProp = propertyRegex.exec(this.document.getText())) !== null) {
        propertyPositionsResults.push(matchProp.index + matchProp[0].lastIndexOf(matchProp[1]));
        propertyPositionsResults.push(matchProp.index + matchProp[0].lastIndexOf(matchProp[1])+matchProp[1].length);
        const propertieMap = createPropertiesMap(propertyPositionsResults,this.document);
        console.log(propertieMap.get(0)?.propertyName);
        //checkProperties(extraxtProperties(propertyPositionsResults));
        propertyPositionsResults.pop();propertyPositionsResults.pop();
        }
    }
}